ControlPropertyState.AutoRuleBindingString:
ForAll(
    Filter(Inventories, cr31c_expiration < Today()),
    Patch(
        ArchivedInventories,
        Defaults(ArchivedInventories),
        {
            cr31c_name: cr31c_name,
            cr31c_batch: cr31c_batch,
            cr31c_expiration: cr31c_expiration,
            cr31c_quantity: cr31c_quantity,
            cr31c_manufacturer_lookup: cr31c_manufacturer_lookup,
            cr31c_itemid: cr31c_itemid,
            archived_date: Today(),
            archive_reason: "Expired"
        }
    )
);
ForAll(
    Filter(Inventories, cr31c_expiration < Today()),
    Remove(Inventories, ThisRecord)
);
Notify("Expired items archived successfully", NotificationType.Success)

If(
    Len(BarcodeScanner1_1.Value) >= 17,
    Set(varBarcodeData,
        With(
            {
                BC: BarcodeScanner1_1.Value,
                IsValid: And(StartsWith(BarcodeScanner1_1.Value, "01"), Len(BarcodeScanner1_1.Value) >= 17)
            },
            If(IsValid,
                {
                    ItemID: Mid(BC, 3, 14),
                    Expiration: If(
                        And(Len(BC) >= 25, Mid(BC, 17, 2) = "17"),
                        Mid(BC, 19, 6),
                        ""
                    ),
                    Batch: If(
                        And(Len(BC) >= 27, Mid(BC, 25, 2) = "10"),
                        Mid(BC, 27, Len(BC) - 26),
                        ""
                    ),
                    ExpirationFormatted: If(
                        And(Len(BC) >= 25, Mid(BC, 17, 2) = "17"),
                        Date(
                            2000 + Value(Mid(BC, 19, 2)),
                            Value(Mid(BC, 21, 2)),
                            Value(Mid(BC, 23, 2))
                        ),
                        Blank()
                    ),
                    IsValidBarcode: true
                },
                {
                    ItemID: "",
                    Expiration: "",
                    Batch: "",
                    ExpirationFormatted: Blank(),
                    IsValidBarcode: false
                }
            )
        )
    );
    If(
        !varBarcodeData.IsValidBarcode,
        Notify("Invalid barcode format. Expected GS1 format starting with '01'", NotificationType.Warning)
    )
)

Set(varShowExpired, !varShowExpired);
        If(varShowExpired,
            Notify("Showing expired items only", NotificationType.Information),
            Notify("Showing all items", NotificationType.Information)
        )

Remove(Inventories, selectedRecord);
If(
    IsEmpty(Errors(Inventories, selectedRecord)),
    UpdateContext({
        CurrentItem: First(Table1_2.SelectedItems),
        isItemSelected: false,
        newMode: false,
        deleteMode: false
    });
    Notify("Item deleted successfully", NotificationType.Success, 3000),
    Notify("Failed to delete item: " & First(Errors(Inventories, selectedRecord)).Message, NotificationType.Error, 5000)
)

UpdateContext({ 
    CurrentItem: Self.LastSubmit, 
    isItemSelected: false,
    newMode: false,
    editMode: false
});
Notify(
    If(newMode, "New item created successfully", "Item updated successfully"), 
    NotificationType.Success,
    3000
);
ResetForm(Form1_2);
Set(varBarcodeData, Blank())
